+            try self.records.append(self.allocator, record);
+            try self.output.append(self.allocator, record.formatted);
+        }
+
+        // Check assertions
+        if (self.no_logs) {
+            if (self.records.items.len > 0) {
+                return error.UnexpectedLogsDetected;
+            }
+        } else {
+            if (self.records.items.len == 0) {
+                return error.NoLogsDetected;
